  <script>
    // Helper to prepend to a log box
    function addLog(el, text, color) {
      const time = new Date().toLocaleTimeString();
      const line = document.createElement('div');
      line.textContent = '[' + time + '] ' + text;
      if (color) line.style.color = color;
      el.prepend(line);
      // keep log length reasonable
      while (el.children.length > 200) el.removeChild(el.lastChild);
    }

    // ------- Buggy counter -------
    (function(){
      let count = 0; // shared state for buggy counter
      const display = document.getElementById('bug-count');
      const incBtn = document.getElementById('bug-inc');
      const resetBtn = document.getElementById('bug-reset');
      const log = document.getElementById('bug-log');
      const delayInput = document.getElementById('bug-delay');

      function render() {
        display.textContent = String(count);
      }

      // Simulated asynchronous read-modify-write that is NOT atomic
      function buggyIncrement() {
        const localRead = count;
        addLog(log, 'read=' + localRead + ' (start async)', '#b33');
        const delay = Math.max(0, parseInt(delayInput.value) || 0);
        // simulate unpredictable async latency
        setTimeout(() => {
          const newVal = localRead + 1;
          addLog(log, 'writing newVal=' + newVal + ' (based on read=' + localRead + ')', '#a33');
          // write to the shared state
          count = newVal;
          render();
        }, delay + Math.random() * delay); // vary latency
      }

      incBtn.addEventListener('click', () => {
        buggyIncrement();
      });

      resetBtn.addEventListener('click', () => {
        count = 0;
        render();
        addLog(log, 'reset -> 0', '#333');
      });

      render();
      addLog(log, 'ready (buggy)', '#333');
    })();

    // ------- Fixed counter (operation queue) -------
    (function(){
      let count = 0; // shared state for fixed counter
      const display = document.getElementById('fix-count');
      const incBtn = document.getElementById('fix-inc');
      const resetBtn = document.getElementById('fix-reset');
      const log = document.getElementById('fix-log');
      const delayInput = document.getElementById('fix-delay');

      function render() {
        display.textContent = String(count);
      }

      // A simple queue: each enqueued function runs after the previous completes.
      // Each operation must return a Promise that resolves when it's done.
      const opQueue = [];
      let running = false;

      function runNext() {
        if (running) return;
        const next = opQueue.shift();
        if (!next) return;
        running = true;
        next().then(() => {
          running = false;
          runNext();
        });
      }

      function enqueueOp(op) {
        opQueue.push(op);
        runNext();
      }

      // The operation: read current count, wait (async), then write count+1
      function fixedIncrement() {
        enqueueOp(() => {
          return new Promise((resolve) => {
            const localRead = count;
            addLog(log, 'read=' + localRead + ' (queued op start)', '#136');
            const delay = Math.max(0, parseInt(delayInput.value) || 0);
            setTimeout(() => {
              // when this runs, count may have changed because previous ops already applied
              const newVal = count + 1; // use current shared count, not stale localRead
              addLog(log, 'writing newVal=' + newVal + ' (based on current count)', '#0a6');
              count = newVal;
              render();
              // small tick to help visual ordering
              setTimeout(resolve, 0);
            }, delay + Math.random() * delay);
          });
        });
      }

      incBtn.addEventListener('click', () => {
        fixedIncrement();
      });

      resetBtn.addEventListener('click', () => {
        // clearing the queue and resetting state
        while (opQueue.length) opQueue.pop();
        count = 0;
        render();
        addLog(log, 'reset -> 0 (queue cleared)', '#333');
      });

      render();
      addLog(log, 'ready (fixed)', '#333');
    })();
  </script>
